/*
输入n
循环遍历1~n
	输入a[i]
循环遍历1~n
	循环遍历1~n
		循环遍历1~n-j+1
			状态转移
输出结果 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
int n;
int dp[2005][2005][2];
int a[2005];
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= n; i++) {
		dp[i][i][0] = 1;
	}
	for (int len = 1; len <= n; len++) {
		for (int i = 1, j = i + len; j <= n; i++, j++) {
			if (a[i] < a[i + 1]) {
				dp[i][j][0] += dp[i + 1][j][0];
			}
			if (a[i] < a[j]) {
				dp[i][j][0] += dp[i + 1][j][1];
			}
			if (a[j] > a[i]) {
				dp[i][j][1] += dp[i][j - 1][0];
			}
			if (a[j] > a[j - 1]) {
				dp[i][j][1] += dp[i][j - 1][1];
			}
			dp[i][j][0] %= 19650827;
			dp[i][j][1] %= 19650827;
		}
	}
	cout << (dp[1][n][0] + dp[1][n][1]) % 19650827;
	return 0;
}
